uint8_t i2cReadByte(uint8_t addr) {
  Wire.requestFrom(addr, (uint8_t)1);
  if (Wire.available()) {
    return Wire.read();
  }
  return 0;
}

void i2cScanner() {
  byte error, address;
  int nDevices = 0;
  Serial.println("开始扫描 I2C 总线...");
  for(address = 1; address < 127; address++ ) {
    Wire.beginTransmission(address);
    error = Wire.endTransmission();
    if (error == 0) {
      Serial.print("发现设备，地址: 0x");
      if (address < 16) Serial.print("0");
      Serial.print(address, HEX);
      Serial.println("  !");
      nDevices++;
    } else if (error == 4) {
      Serial.print("地址 0x");
      if (address < 16) Serial.print("0");
      Serial.println(address, HEX);
      Serial.println(" 发生未知错误");
    }
  }
  if (nDevices == 0) Serial.println("未发现任何 I2C 设备\n");
  else Serial.println("扫描完成\n");
}

void canSendByte(uint32_t id, uint8_t data) {
  CAN_message_t msg;
  msg.id = id;
  msg.len = 1;
  msg.buf[0] = data;
  CAN.write(msg);
}

uint8_t canReadByte() {
  CAN_message_t msg;
  if(CAN.read(msg)) {
    return msg.buf[0];
  }
  return 0;
}

long readUltrasonicDistance(int triggerPin, int echoPin) {
  digitalWrite(triggerPin, LOW);
  delayMicroseconds(2);
  digitalWrite(triggerPin, HIGH);
  delayMicroseconds(10);
  digitalWrite(triggerPin, LOW);
  return pulseIn(echoPin, HIGH) * 0.034 / 2;
}

