int readVL53L0X() {
  VL53L0X_RangingMeasurementData_t measure;
  lox.rangingTest(&measure, false); 
  if (measure.RangeStatus != 4) {  // Phase failure 代表超出范围或读取错误
    return measure.RangeMilliMeter;
  } else {
    return -1; // -1 表示测量无效
  }
}

