void neopixel_rainbow_6(int wait) {
  for(long firstPixelHue = 0; firstPixelHue < 5*65536; firstPixelHue += 256) {
    for(int i=0; i<strip_6.numPixels(); i++) {
      int pixelHue = firstPixelHue + (i * 65536L / strip_6.numPixels());
      strip_6.setPixelColor(i, strip_6.gamma32(strip_6.ColorHSV(pixelHue)));
    }
    strip_6.show();
    delay(wait);
  }
}

