const byte addr_Reading[] = "00001";
radio.openReadingPipe(1, addr_Reading); // Note: Reading pipe needs index (1-5), Writing does not (or ignores it)
// Correcting standard lib usage:
// radio.openWritingPipe(address) -> takes address
// radio.openReadingPipe(number, address) -> takes index and address
if ("Reading" == "Writing") {
 radio.openWritingPipe(addr_Reading);
} else {
 radio.openReadingPipe(1, addr_Reading);
}

